  final exactMatch = _extensionRequests
      .where((r) => r.scheduleId == schedule.id)
      .firstOrNull;
  if (exactMatch != null) return exactMatch;

  // For accepted requests, check if this schedule is part of either
  // swapped period. After a full-period swap:
  // - The requester's original period dates now have nextUserId
  // - The next user's original period dates now have requesterId
  // We need to find the request where this schedule's date falls near
  // the anchor schedule's date range.

  // Find the anchor schedule for each accepted request to check proximity
