    // Find the anchor schedule in our loaded schedules
    final anchor = _schedules.where((s) => s.id == r.scheduleId).firstOrNull;
    if (anchor == null) continue;

    // Check if this schedule is within a reasonable range of the anchor
    // (within cleaningPeriodDays * 2 + daysBetweenUsers days)
    // and involves one of the two swapped users
    final daysDiff = schedule.date.difference(anchor.date).inDays.abs();
    if (daysDiff > 30) continue; // Skip if too far away

