### 1. Create RealtimeService — lib/core/realtime_service.dart:
A lightweight service that manages Supabase Realtime channel subscriptions and exposes callback-based listeners.

```dart
import 'dart:async';
import 'package:flutter/foundation.dart';
import 'package:flutter_cleanapp/core/supabase_config.dart';
import 'package:supabase_flutter/supabase_flutter.dart';

class RealtimeService {
  RealtimeService._();
  static final RealtimeService instance = RealtimeService._();

  RealtimeChannel? _channel;

  final _schedulesController = StreamController<void>.broadcast();
  final _tasksController = StreamController<void>.broadcast();
  final _commentsController = StreamController<void>.broadcast();
  final _extensionsController = StreamController<void>.broadcast();

  Stream<void> get onSchedulesChanged => _schedulesController.stream;
  Stream<void> get onTasksChanged => _tasksController.stream;
  Stream<void> get onCommentsChanged => _commentsController.stream;
  Stream<void> get onExtensionsChanged => _extensionsController.stream;

  void subscribe() {
    _channel?.unsubscribe();
    _channel = SupabaseConfig.client.channel('app_changes')
      .onPostgresChanges(
        event: PostgresChangeEvent.all,
        schema: 'public',
        table: 'schedules',
        callback: (payload) => _schedulesController.add(null),
      )
      .onPostgresChanges(
        event: PostgresChangeEvent.all,
        schema: 'public',
        table: 'tasks',
        callback: (payload) => _tasksController.add(null),
      )
      .onPostgresChanges(
        event: PostgresChangeEvent.all,
        schema: 'public',
        table: 'comments',
        callback: (payload) => _commentsController.add(null),
      )
      .onPostgresChanges(
        event: PostgresChangeEvent.all,
        schema: 'public',
        table: 'extension_requests',
        callback: (payload) => _extensionsController.add(null),
      )
      .subscribe();
  }

  void unsubscribe() {
    _channel?.unsubscribe();
    _channel = null;
  }

  void dispose() {
    unsubscribe();
    _schedulesController.close();
    _tasksController.close();
    _commentsController.close();
    _extensionsController.close();
  }
}
```

