ExtensionRequest? _getRequestForSchedule(CleaningSchedule schedule) {
  // First try exact match by scheduleId (covers the original/requester schedule)
  final exactMatch = _extensionRequests
      .where((r) => r.scheduleId == schedule.id)
      .firstOrNull;
  if (exactMatch != null) return exactMatch;

  // For accepted requests, also check if this schedule was the 'other side' of a swap.
  // After acceptance, the next user's schedule now has requesterId as its userId.
  // So if schedule.userId == request.requesterId AND the request is accepted,
  // this schedule was the one that received the requester in the swap.
  return _extensionRequests
      .where((r) =>
          r.status == ExtensionRequestStatus.accepted &&
          r.requesterId == schedule.userId)
      .firstOrNull;
}
