```dart
/// Checks if the user has already used their prórroga for the current cycle.
///
/// A user gets 1 prórroga per cycle. A cycle is the period between the user's
/// previous cleaning period and their current one. We approximate this by
/// checking for any accepted prórroga where the user is the requester and
/// the request was created within the last 30 days.
Future<void> _checkProrrogaLimit() async {
  try {
    final accepted = await SupabaseService.instance
        .getAcceptedRequestsForRequester(widget.currentUser.id);

    // Find the user's previous period end date to define the cycle window.
    // Simple approach: check if any accepted request exists where the
    // anchor schedule date is after the user's last completed period.
    // Simplest: any accepted request in the last 30 days counts.
    final cutoff = DateTime.now().subtract(const Duration(days: 30));
    final recentAccepted = accepted.where(
      (r) => r.createdAt.isAfter(cutoff),
    );

    if (mounted) {
      setState(() => _hasExceededProrrogaLimit = recentAccepted.isNotEmpty);
    }
  } catch (_) {
    // Non-fatal — default to false (allow request)
  }
}
```

